parameters.functionCode:
// Generate a stable echo_id
const crypto = require('crypto');

const echoId = `echo-${crypto.randomUUID()}`;

return [
  {
    json: {
      echo_id: echoId,
      ...($json.body)
    }
  }
];

// Build EchoMoment JSON matching /schemas/EchoMoment.schema.json
const data = $json;

const echoMoment = {
  schema_version: "1.0.0",
  echo_id: data.echo_id,
  moment_type: data.moment_type || "memory",
  title: data.title,
  subtitle: data.subtitle || undefined,
  narrative: data.narrative || "",
  created_at: new Date().toISOString(),
  creator: {
    actor_id: data.creator_id || "system",
    display_name: data.creator_name || "NOIZY System",
    brand_home: data.brand_home || "NOIZY"
  },
  sovereignty: {
    consent_required: true,
    provenance_required: true,
    receipt_required: true
  },
  sensory: {
    tags: data.sensory_tags || [],
    mood: Array.isArray(data.mood) ? data.mood : (data.mood ? [data.mood] : [])
  },
  links: {
    artifact_ids: [],
    manifest_ids: [],
    receipt_ids: [],
    memcell_ids: []
  }
};

return [{ json: echoMoment }];

